//Websocket client
class Lock {
  constructor() {
    this.flag = false;
    this.data = {}; // 这个data可以根据业务需要保留或移除，是用于传递值的。
  }

  wait() { // 等待锁
    return new Promise(resolve => {
      if (this.flag) {
        resolve(this.data);
      } else {
        this.resolve = resolve;
      }
    });
  }

  notify(data = {}) { // 通知锁
    this.data = data;
    this.flag = true;
    this.resolve && this.resolve(this.data);
  }
}
export default function WebsocketClient(server_ip, server_port, protocol = "ws"){
    this.ws = new WebSocket(protocol+"://"+server_ip+":" + server_port);
    this.msgHandler = null;
    this.onopen = function (){};
    let obj = this;
    this.sendData = function (data) {
        obj.ws.send(JSON.stringify(data));
    };
    this.setMsgHandler = function (handler){
        obj.msgHandler = handler;
    }
    this.ws.onopen = function() {
        obj.onopen();
    };
    this.ws.onmessage = function (event) {
        let data = JSON.parse(event.data);
        if (typeof obj.msgHandler[data.action] === 'function') {
            obj.msgHandler[data.action](data.value);
        } else {
            console.error('Unkown msg type: ' + data.type);
        }
    }
    this.ws.onclose = function () {
        reconnect(server_ip, server_port);
    };
    this.ws.onerror = function () {
        reconnect(server_ip, server_port);
    };
    // 重连
    var lock = new Lock();
    var timeConnect = 0;
    async function reconnect() {
        // lockReconnect加锁，防止onclose、onerror两次重连
        // lock.wait();
        var timeoutObj = setInterval( () => {
            // 进行重连
            if(obj.ws){
                if(obj.ws.readyState != 1){
                    timeConnect++;
                    if(timeConnect < 10){
                        console.log("第" + timeConnect + "次重连");
                        obj.ws = new WebSocket(protocol+"://"+server_ip+":" + server_port);
                        if(obj.ws.readyState === 1){
                            lock.notify();
                            clearInterval(timeoutObj);
                        }
                    }
                }else{
                    // lock.notify();
                    clearInterval(timeoutObj);
                }
            }
        }, 1000);
    }
}