import { logEvent } from "firebase/analytics";
import { analytics } from "./firebase.js";
export default class Chat {
    constructor (ws, player, videoNode, boxNode, audioOnly = false) {        
        this.ws = ws;
        this.player = player;
        this.videoNode = videoNode;
        this.boxNode = boxNode;
        this.audioOnly = audioOnly;
        this.mediaStream = null;
        this.pc = null;
        this.remoteUserId = "123";
        this.candidates = [];
        this.setedRemoteDesc = false;
        this.phoneWidth = 0;
        this.phoneHeight = 0;
    }
    initConnect () {
        this.pc = new window.RTCPeerConnection();
        // 向对方发送nat candidate
        this.pc.onicecandidate = event => {
            if (!event.candidate) {
                return;
            }
            console.log('send remote with my nat candidate', event.candidate);
			let v={};
			Object.assign(v, {sdp: event.candidate.candidate}, {sdpMLineIndex: event.candidate.sdpMLineIndex}, {sdpMid: event.candidate.sdpMid});
            this.ws.sendData({
                action: 'addIceCandidate',
                value: v
            });
        };
        let codecList = null;

        this.pc.addEventListener("icegatheringstatechange", (event) => {
          if (this.pc.iceGatheringState === "complete") {
            const receivers = this.pc.getReceivers();

            receivers.forEach((receiver) => {
              if (receiver.track.kind === "video") {
                codecList = receiver.getParameters().codecs;
                return;
              }
            });
          }

          codecList = null;
        });
        // 收到对方的视频流
        let playing = false
        var obj = this
        this.pc.onaddstream = event => {
			if (obj.player) {
                if (!obj.audioOnly ) {
                    const videoDom = obj.player.tech().el()
                    videoDom && (videoDom.srcObject = event.stream)
    
                    videoDom.oncanplay = event =>{
                        console.log('oncanplay event', event)
                    }
                    obj.player.play = () => {
                        videoDom.play()
                        logEvent(analytics, 'webrtc_video_play', {});
                    }
                    if (!playing) {
                        obj.player.play()
                        playing = true
                    }
                }else{
                    obj.player.srcObject = event.stream
                }

            }
			return false;
        };
        // 对方关闭
        this.pc.oniceconnectionstatechange = event => {
            console.log('signalingstatechange', this.pc.iceConnectionState);
            if (!this.audioOnly && this.pc.iceConnectionState === 'disconnected') {                
                obj.videoNode.srcObject = null;
                this.stopMyVideo();
                obj.boxNode.style.display = 'none';
            }
        };
    }
    addCandidate (candidate) {
        // console.log('addCandidate', candidate);
        candidate && this.candidates.push(candidate);
        if (this.setedRemoteDesc) {
            this.candidates.forEach(candidate => {
                this.pc.addIceCandidate(new RTCIceCandidate(candidate));
            });
        }
        //var receivers = this.pc.getReceivers()
        //console.log(receivers)
        //var transceivers = this.pc.getTransceivers()
        //console.log(transceivers)
    }
    ring () {        
        this.ws.sendData({
            action: 'setUpCall',
            value: {
                remoteUserId: this.remoteUserId
            }
        });
    }
    // 收到对方的offer后进行响应
    async answer (offer) {
        // open要在setRemote之前，不然不会触发对方的addstream事件
        if(!this.audioOnly) this.boxNode.style.display = 'flex';
        //console.log('this.pc.setRemoteDescription');
		//let off = await this.pc.createOffer()
		//console.log('off', off)
        await this.pc.setRemoteDescription(offer);
		//console.log('setRemoteDescription', offer)
		let localDesc = await this.pc.createAnswer()
		//console.log('setLocalDescription', localDesc)
        await this.pc.setLocalDescription(localDesc);
        //console.log('this.pc.localDescription', this.pc.localDescription);
        this.ws.sendData({
            action: 'setSessionDescription',
            value: this.pc.localDescription.sdp
        });
        this.setedRemoteDesc = true;
        this.addCandidate();
    }
    async onRecvAnswer (offer) {
        console.log('onRecvAnswer', offer);
        //console.log('this.pc.setRemoteDescription');
		let off = await this.pc.createOffer()
		//console.log('offer', off)
        await this.pc.setRemoteDescription(offer);
        this.setedRemoteDesc = true;
        this.addCandidate();
    }
    async call () {
        this.initConnect();
        if(!this.audioOnly) this.boxNode.style.display = 'flex';
        //await this.openMyCamera();
        //this.sendOffer();
    }
    async sendOffer () {
        let offer = await this.pc.createOffer({
            offerToReceiveAudio: true,
            offerToReceiveVideo: true
        });
        await this.pc.setLocalDescription(offer);
        this.ws.sendData({
            type: 'offer',
            data: {
                desc: this.pc.localDescription
            }
        });
        // console.log(offer.sdp);
        // this.pc.setRemoteDescription(remoteOffer);
        // var candidate = new RTCIceCandidate(remoteCandidate);
        // this.pc.addIceCandidate(candidate);
    }
    stopMyVideo () {
        if (this.mediaStream) {
            this.mediaStream.getVideoTracks()[0].stop();
        }
    }
    closeConnection () {
        this.pc.close();
        if(!this.audioOnly){
            this.stopMyVideo();
            this.boxNode.style.display = 'none';
        }
    }
}