import { logEvent } from "firebase/analytics";
import { analytics } from "./firebase.js";
import WebsocketClient from "./websocket-client.js";
import RemoteKeyboard from "./remote-keyboard.js";
import GestureBuilder from "./gesture-builder.js";
import Chat from "./chat.js";
import videojs from "video.js";
require("./videojs-unmute.min.js");
const $ = document.querySelector.bind(document);

//Check browser support
if (!window.WebSocket) {
    alert("FATAL: WebSocket not natively supported. This program will not work!");
    throw SyntaxError();
}
if (!window.RTCPeerConnection) {
    alert('你的浏览器不支持WebRTC，无法使用');
    throw SyntaxError();
}
//Preparation
// videojs-unmute require id=vid1
var player = videojs('vid1', {
        autoplay: true
});
player.unmuteButton();

var currentChat = null;
var remoteUserId = 0;
var phoneWidth = 0;
var phoneHeight = 0;
var scaleApp = 1
var scaleBrowser = 1; //scale in browser window
var server_ip = window.location.hostname;
var server_port = window.ws_port;
var ws = new WebsocketClient(server_ip, server_port, window.ws_protocol);

var gestureBuilder = new GestureBuilder($('#gestureArea'), ws);
var remoteKeyboard = new RemoteKeyboard(ws);
//var remoteClipboard = new RemoteClipboard(ws);

var currentChat;
const msgHandler_old = {

    changeVideoSize(data) {
        location.reload()  //reload when phone orientation changed
    },

}
const msgHandler = {
    error (data) {
        util.showTip(data.msg, 'error');
    },
    setFullscreenSize(data) {
        gestureBuilder.setFullscreenSize(data.width, data.height)
    },
    changeVideoSize (data) {
        var backWidth = window.innerWidth;
        var backHeight = window.innerHeight;
        var width;
        var height;
        var scaleBrowser;

        if(data.width <= backWidth && data.height <= backHeight){//keep show area unchanged
            width = data.width;
            height = data.height;
        }else if(data.width > backWidth && data.height <= backHeight){ //use screen width, scaled height
            scaleBrowser = data.width / backWidth;
            width = backWidth;
            height = Math.floor(data.height / scaleBrowser);
        }else if(data.width <= backWidth && data.height > backHeight){ //use scaled width, screen height
            scaleBrowser = data.height / backHeight;
            width = Math.floor(data.width / scaleBrowser);
            height = backHeight;
        }else if(data.width > backWidth && data.height > backHeight){
            var scaleHeight = data.height / backHeight;
            var scaleWidth = data.width / backWidth;
            if(scaleHeight >= scaleWidth) { //use scaled width, screen height
                scaleBrowser = scaleHeight;
                width = Math.floor(data.width / scaleBrowser);
                height = backHeight;
            }else{ //use screen width, scaled height
                scaleBrowser = scaleWidth;
                width = backWidth;
                height = Math.floor(data.height / scaleBrowser);
            }
        }

        $('.remote-video').style.width = width + 'px';
        $('.remote-video').style.height = height + 'px';
        $('.video-innerbox').style.width = width + 'px';
        $('.video-innerbox').style.height = height + 'px';
        gestureBuilder && gestureBuilder.refreshPz();
        //scale = Math.max(phoneWidth, phoneHeight) / Math.max(width, height);
        //currentChat.gestureBuilder && currentChat.gestureBuilder.refreshPz();
    },

    // 收到对方发给我的candidate
    addIceCandidate (data) {
        console.log('recv remote nat candidate', data);
        let v={};
        Object.assign(v, {candidate: data.sdp}, {sdpMLineIndex: data.sdpMLineIndex}, {sdpMid: data.sdpMid});

        currentChat.addCandidate(v);
    },
    // 收到对方的offer
    setSessionDescription (data) {
        console.log('setSessionDescription', data);
        logEvent(analytics, 'set_sdp', {});
        let offer = new RTCSessionDescription();
        offer.type = 'offer';
        offer.sdp = data;
        //let offer = data.desc;
        currentChat.answer(offer);
    },
    // 收到对方的answer
    answer (data) {
        //let offer = data.desc;
        currentChat.onRecvAnswer(data);
    },
    handlerError(data) {
    }
}

ws.setMsgHandler(msgHandler)
ws.onopen = async function() {
    $("#server_status").style.display='none';
    var table = document.getElementById('head_table');
    table.style.display = 'none';    
    currentChat && currentChat.closeConnection();    
    let chat = new Chat(ws, player, $(".remote-video"), $(".video-box"));
    ws.sendData({
        action: 'setResizeFactor',
        value: {
            browserWidth: window.innerWidth * window.devicePixelRatio,
            browserHeight: window.innerHeight * window.devicePixelRatio
        }
    });
    currentChat = chat;
    chat.initConnect();
    chat.ring();
}
logEvent(analytics, 'webrtc_loaded', {});
